    /* Data gathered by scraping the html page
     *
     * _9lHjd is the main box containing the section identifiers and description
     * Z_M4- is the section identifiers
     * Stq7y is the description
     *
     * JSON.stringify(Array.from(document.querySelectorAll('._9lHjd')).map(x => ({title: x.querySelector('.Z_M4-')?.innerText, desc: x.querySelector('.Stq7y')?.innerText})).filter(x => x.title && x.desc)).replace(/:/g, '=>').replace(/{/g, '[').replace(/}/g, ']')
     */

    /**
     * Run the database seeds.
     */
    public function run(): void {
        $data = $this->getData();

        foreach ($data as $section) {
            $sectionNumber = 0;
            $unitNumber = 0;

            if (preg_match('/Section (\d+), Unit (\d+)/i', $section['title'], $matches)) {
                $sectionNumber = (int) $matches[1];
                $unitNumber = (int) $matches[2];
            }

            Section::query()
                ->where('section_number', $sectionNumber)
                ->where('unit_number', $unitNumber)
                ->update(['description' => $section['desc']]);
        }
    }

